require\('dotenv/config'\);
const { Pool } = require\('pg'\);
const pool = new Pool\({ connectionString: process.env.DATABASE_URL }\);

async function main\(\) {
  // Fetch the most recent tender
  const { rows } = await pool.query\('SELECT * FROM tenders WHERE allow_translation = true ORDER BY created_at DESC LIMIT 1'\);
  const tender = rows[0];
  if \(!tender\) { console.log\('No tender found'\); return; }
  console.log\('Tender:', tender.id, tender.title, 'lang:', tender.language\);

  // Collect translatable fields
  const keys = [], texts = [];
  const tgtLang = tender.language === 'ar' ? 'en' : 'ar';

  if \(tender.title\) { keys.push\('title'\); texts.push\(tender.title\); }
  if \(tender.description\) { keys.push\('description'\); texts.push\(tender.description\); }
  if \(tender.objective\) { keys.push\('objective'\); texts.push\(tender.objective\); }
  if \(tender.category\) { keys.push\('category'\); texts.push\(tender.category\); }

  const deliverables = tender.deliverables || [];
  deliverables.forEach\(\(d, i\) => {
    const name = typeof d === 'string' ? d : d?.name;
    if \(name\) { keys.push\('deliverable_name_' + i\); texts.push\(name\); }
    if \(typeof d !== 'string' && d?.description\) { keys.push\('deliverable_desc_' + i\); texts.push\(d.description\); }
  }\);

  console.log\('Texts to translate \(' + tgtLang + '\):', texts.length\);

  // Call the live /api/translate
  const res = await fetch\('http://localhost:5000/api/translate', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify\({ texts, targetLanguage: tgtLang }\),
  }\);
  const data = await res.json\(\);
  console.log\('Translations received:', data.translations?.length\);

  // Build the map
  const map = {};
  keys.forEach\(\(key, idx\) => { map[key] = data.translations[idx]; }\);
  const translatedContent = { [tgtLang]: map };
  console.log\('translatedContent:', JSON.stringify\(translatedContent, null, 2\)\);

  // Save to DB
  await pool.query\('UPDATE tenders SET translated_content = \\$1 WHERE id = \\$2', [JSON.stringify\(translatedContent\), tender.id]\);
  console.log\('Saved to DB!'\);

  // Verify
  const check = await pool.query\('SELECT translated_content FROM tenders WHERE id = \\$1', [tender.id]\);
  console.log\('Verified:', check.rows[0].translated_content !== null ? 'HAS CONTENT' : 'NULL'\);

  pool.end\(\);
}
main\(\).catch\(e => { console.error\(e\); pool.end\(\); }\);
" 2>&1)

